import './TimelineAtom.scss';

import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC } from 'react';
import React, { useMemo } from 'react';

import { classNames } from '../../../helpers/classnames';
import { Icon } from '../../Icon';
import type { TimelineAtomProps } from './TimelineAtom.types';

export const TimelineAtom: FC<TimelineAtomProps> = ({
	type = 'current',
	position = 'top',
	direction = 'vertical',
	iconName,
	collapsable = false,
	collapsed = false,
}) => {
	/** Возвращает иконку для Атома(кружочек) активного шага:
	 * Если шаг с ошибкой: иконка "крестик"
	 * Если шаг последний: иконка "галочка"
	 * Если шаг непоследний: иконка "шеврон вниз"
	 * */
	const getAtomIconName = useMemo(() => {
		if (iconName) {
			return iconName;
		}

		if (type === 'error') {
			return Icons.Close;
		}

		if (position === 'bottom') {
			return Icons.Check;
		}

		return Icons.FastArrowDown;
	}, [iconName, type, position]);

	const atomClasses = classNames('dsb_atom', `dsb_atom__${direction}`, `dsb_atom__${position}`);

	const contentClasses = classNames(
		'dsb_atom-content',
		collapsable && collapsed && 'dsb_atom-content__collapsed',
		`dsb_atom-content__${position}`,
		`dsb_atom-content__${type}`,
		`dsb_atom-content__${direction}`,
	);

	return (
		<div data-testid="TimelineAtom" className={atomClasses}>
			<div className={contentClasses}>
				<div className={classNames('dsb_atom-icon', `dsb_atom-icon__${type}`)}>
					{(type === 'current' || type === 'error') && <Icon size="medium" iconName={getAtomIconName} />}
				</div>
			</div>
		</div>
	);
};
